/**
 * Removes stale Next.js generated type directories before running tsc.
 *
 * `.next/types/`       — generated by `next build`; may reference deleted routes.
 * `.next/dev/`         — generated by `next dev` / Turbopack; may reference routes
 *                        that were added to the dev server but not yet committed.
 * `.next-e2e/types/`  — same as above but for the e2e test build (NEXT_DIST_DIR=.next-e2e).
 * `.next-e2e/dev/`    — same as above for Turbopack e2e dev server.
 *
 * Deleting these ensures `tsc --noEmit` always checks against the live source
 * tree rather than potentially stale auto-generated validators.
 */

const { rmSync } = require('fs');
const { join } = require('path');

const root = join(__dirname, '..');

for (const dir of ['.next/types', '.next/dev', '.next-e2e/types', '.next-e2e/dev']) {
  rmSync(join(root, dir), { recursive: true, force: true });
}
